data = {"a": None, "b": {"c": None, "d": [None, 1, None]}, "e": 0}

# 默认：None → ""，处理列表
replace_values(data)
# {"a": "", "b": {"c": "", "d": ["", 1, ""]}, "e": 0}

# 把 None 和 0 都替换成 "N/A"
replace_values(data, target_types=(type(None), int), replacement="N/A")
# {"a": "N/A", "b": {"c": "N/A", "d": ["N/A", "N/A", "N/A"]}, "e": "N/A"}

# 不处理列表内元素
